#!/usr/bin/env python3 """ hierarchical_chunker.py Token-aware parent-child document chunking. Splits massive unstructured sources into hierarchical context blocks: document section paragraph (parent-child graph) Usage: python hierarchical_chunker.py --file path/to/doc.txt python hierarchical_chunker.py --text "..." --async-batch """ from __future__ import annotations import argparse import asyncio import hashlib import json import re import uuid from dataclasses import dataclass, field from pathlib import Path from typing import Any, Dict, List, Optional, Tuple # Token estimation: ~4 chars/token (conservative for English prose) CHARS_PER_TOKEN = 4 DEFAULT_PARENT_TOKENS = 1200 DEFAULT_CHILD_TOKENS = 300 DEFAULT_OVERLAP_TOKENS = 40 SECTION_PATTERN = re.compile( r"^(#{1,6}\s+.+|[A-Z][A-Z0-9 \-]{4,}$|\d+\.\s+[A-Z].+)$", re.MULTILINE, ) def estimate_tokens(text: str) -> int: return max(1, len(text) // CHARS_PER_TOKEN) def _chunk_id(*parts: str) -> str: raw = "|".join(parts)[:512] return hashlib.sha256(raw.encode("utf-8")).hexdigest()[:20] @dataclass class ChunkNode: chunk_id: str level: str # document | section | paragraph text: str token_count: int parent_id: Optional[str] = None document_id: str = "" source_path: str = "" content_hash: str = "" ordinal: int = 0 metadata: Dict[str, Any] = field(default_factory=dict) def to_dict(self) -> Dict[str, Any]: return { "chunk_id": self.chunk_id, "level": self.level, "text": self.text, "token_count": self.token_count, "parent_id": self.parent_id, "document_id": self.document_id, "source_path": self.source_path, "content_hash": self.content_hash, "ordinal": self.ordinal, "metadata": self.metadata, } def _split_by_tokens(text: str, max_tokens: int, overlap_tokens: int = 0) -> List[str]: if not text.strip(): return [] max_chars = max_tokens * CHARS_PER_TOKEN overlap_chars = overlap_tokens * CHARS_PER_TOKEN if len(text) <= max_chars: return [text.strip()] chunks: List[str] = [] start = 0 while start < len(text): end = min(len(text), start + max_chars) if end < len(text): break_at = text.rfind("\n\n", start, end) if break_at > start + max_chars // 3: end = break_at else: break_at = text.rfind(" ", start, end) if break_at > start + max_chars // 3: end = break_at piece = text[start:end].strip() if piece: chunks.append(piece) if end >= len(text): break start = max(start + 1, end - overlap_chars) return chunks def _detect_sections(text: str) -> List[Tuple[str, str]]: """Return (heading, body) sections; fallback to single document body.""" matches = list(SECTION_PATTERN.finditer(text)) if not matches: return [("", text)] sections: List[Tuple[str, str]] = [] for i, m in enumerate(matches): heading = m.group(0).strip() body_start = m.end() body_end = matches[i + 1].start() if i + 1 < len(matches) else len(text) body = text[body_start:body_end].strip() sections.append((heading, body)) preamble = text[: matches[0].start()].strip() if preamble: sections.insert(0, ("", preamble)) return sections class HierarchicalChunker: """Token-aware parent-child chunking for semantic indexing.""" def __init__( self, *, parent_max_tokens: int = DEFAULT_PARENT_TOKENS, child_max_tokens: int = DEFAULT_CHILD_TOKENS, overlap_tokens: int = DEFAULT_OVERLAP_TOKENS, ): self.parent_max_tokens = parent_max_tokens self.child_max_tokens = child_max_tokens self.overlap_tokens = overlap_tokens def chunk_text( self, text: str, *, source_path: str = "", content_hash: str = "", metadata: Optional[Dict[str, Any]] = None, ) -> List[ChunkNode]: text = text.replace("\r\n", "\n").strip() if not text: return [] meta = dict(metadata or {}) doc_id = _chunk_id(source_path or "inline", content_hash or text[:200]) if not content_hash: content_hash = hashlib.sha256(text.encode("utf-8")).hexdigest() nodes: List[ChunkNode] = [] doc_node = ChunkNode( chunk_id=doc_id, level="document", text=text[: min(len(text), self.parent_max_tokens * CHARS_PER_TOKEN * 2)], token_count=estimate_tokens(text), parent_id=None, document_id=doc_id, source_path=source_path, content_hash=content_hash, ordinal=0, metadata={**meta, "full_token_count": estimate_tokens(text)}, ) nodes.append(doc_node) sections = _detect_sections(text) for sec_idx, (heading, body) in enumerate(sections): section_text = f"{heading}\n\n{body}".strip() if heading else body if not section_text: continue parent_parts = _split_by_tokens(section_text, self.parent_max_tokens, self.overlap_tokens) for p_idx, parent_text in enumerate(parent_parts): parent_id = _chunk_id(doc_id, "section", str(sec_idx), str(p_idx)) parent_node = ChunkNode( chunk_id=parent_id, level="section", text=parent_text, token_count=estimate_tokens(parent_text), parent_id=doc_id, document_id=doc_id, source_path=source_path, content_hash=content_hash, ordinal=sec_idx * 100 + p_idx, metadata={**meta, "section_heading": heading or None}, ) nodes.append(parent_node) child_parts = _split_by_tokens(parent_text, self.child_max_tokens, self.overlap_tokens // 2) for c_idx, child_text in enumerate(child_parts): child_id = _chunk_id(parent_id, "paragraph", str(c_idx)) nodes.append( ChunkNode( chunk_id=child_id, level="paragraph", text=child_text, token_count=estimate_tokens(child_text), parent_id=parent_id, document_id=doc_id, source_path=source_path, content_hash=content_hash, ordinal=c_idx, metadata={**meta, "section_heading": heading or None}, ) ) return nodes def chunk_file(self, path: Path) -> List[ChunkNode]: text = path.read_text(encoding="utf-8", errors="replace") content_hash = hashlib.sha256(text.encode("utf-8")).hexdigest() return self.chunk_text(text, source_path=str(path), content_hash=content_hash) async def chunk_file_async(self, path: Path) -> List[ChunkNode]: return await asyncio.to_thread(self.chunk_file, path) async def chunk_files_async(self, paths: List[Path], *, concurrency: int = 8) -> List[ChunkNode]: sem = asyncio.Semaphore(max(1, concurrency)) all_nodes: List[ChunkNode] = [] async def _one(p: Path) -> None: async with sem: nodes = await self.chunk_file_async(p) all_nodes.extend(nodes) await asyncio.gather(*[_one(p) for p in paths]) return all_nodes async def chunk_paths_async(paths: List[str], **kwargs) -> List[Dict[str, Any]]: chunker = HierarchicalChunker(**kwargs) nodes = await chunker.chunk_files_async([Path(p) for p in paths]) return [n.to_dict() for n in nodes] if __name__ == "__main__": parser = argparse.ArgumentParser(description="Hierarchical token-aware chunker") parser.add_argument("--file", type=str) parser.add_argument("--text", type=str) parser.add_argument("--parent-tokens", type=int, default=DEFAULT_PARENT_TOKENS) parser.add_argument("--child-tokens", type=int, default=DEFAULT_CHILD_TOKENS) args = parser.parse_args() chunker = HierarchicalChunker( parent_max_tokens=args.parent_tokens, child_max_tokens=args.child_tokens, ) if args.file: nodes = chunker.chunk_file(Path(args.file)) elif args.text: nodes = chunker.chunk_text(args.text, source_path="stdin") else: sample = ("# Introduction\n\n" + "Semantic retrieval scales with hierarchy. " * 80 + "\n\n" "## Methods\n\n" + "Parent-child chunks preserve context. " * 60) nodes = chunker.chunk_text(sample, source_path="sample") summary = { "total_nodes": len(nodes), "by_level": {}, "sample_ids": [n.chunk_id for n in nodes[:5]], } for n in nodes: summary["by_level"][n.level] = summary["by_level"].get(n.level, 0) + 1 print(json.dumps({"summary": summary, "nodes": [n.to_dict() for n in nodes[:8]]}, indent=2))